// ✅ O(n) — búsqueda en HashSet
public List<Delivery> filterActive(List<Delivery> all, List<String> activeIds) {
    Set<String> idSet = new HashSet<>(activeIds); // O(n) una vez
    return all.stream()
        .filter(d -> idSet.contains(d.getId()))    // O(1) por elemento
        .toList();
}
